"""Run from insightforge root: python3 install_frontend.py

Creates frontend/index.html — a self-contained UI (no npm, no build step).
Open it directly in your browser after starting the backend with `make run`.
"""
import base64
from pathlib import Path
ROOT = Path(__file__).parent
FILES = {
  "frontend/index.html": ""
}
for rel, b64 in FILES.items():
    p = ROOT / rel
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_bytes(base64.b64decode(b64))
    print(f"  wrote {rel}")
print("\nDone! Start the backend (make run), then open frontend/index.html in your browser.")
print("On Mac:  open frontend/index.html")